import { Component, computed, inject, input, OnInit, signal } from '@angular/core';
import { RouterLink } from '@angular/router';
import { forkJoin, of } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { CourseService } from '../../core/services/course.service';
import { QuizService } from '../../core/services/quiz.service';
import { AssignmentService } from '../../core/services/assignment.service';
import { AuthService } from '../../core/services/auth.service';

export type CourseNavKey =
  | 'home' | 'modules' | 'pages' | 'quizzes' | 'assignments' | 'people' | 'syllabus' | 'grades';

export interface CourseNavCounts {
  modules: number;
  pages: number;
  quizzes: number;
  assignments: number;
  people: number;
}

/**
 * Reusable course sidebar (Canvas-style) shared across every course sub-page:
 * course-detail (home/modules/assignments/people/syllabus tabs), the pages
 * routes, and the quizzes routes.
 *
 *   <app-course-nav [courseId]="id" active="quizzes" [counts]="counts" />
 *
 * Section tabs that still live inside course-detail (home, modules, assignments,
 * people, syllabus) link to /courses/:id?section=…; pages and quizzes have their
 * own routes. Pass [counts] to avoid a refetch; omit it and the nav loads its own.
 */
@Component({
  selector: 'app-course-nav',
  standalone: true,
  imports: [RouterLink],
  template: `
    <aside class="cd-nav">
      @for (n of items(); track n.key) {
        <a class="cd-nav-item" [class.active]="active() === n.key"
           [routerLink]="n.link" [queryParams]="n.query">
          <span class="material-icons">{{ n.icon }}</span>
          <span class="cd-nav-label">{{ n.label }}</span>
          @if (n.count !== null) { <span class="cd-nav-count">{{ n.count }}</span> }
        </a>
      }
    </aside>
  `,
  styleUrl: './course-nav.scss',
})
export class CourseNavComponent implements OnInit {
  private cSvc = inject(CourseService);
  private qSvc = inject(QuizService);
  private aSvc = inject(AssignmentService);
  private auth = inject(AuthService);

  readonly courseId = input.required<number>();
  readonly active = input<CourseNavKey>('home');
  /** Optional — when provided the nav skips its own count fetch. */
  readonly counts = input<CourseNavCounts | null>(null);

  private fetched = signal<CourseNavCounts | null>(null);
  private readonly isAdmin = this.auth.hasRole('PlatformAdmin', 'Instructor');

  private readonly effective = computed(() => this.counts() ?? this.fetched());

  readonly items = computed(() => {
    const id = this.courseId();
    const c = this.effective();
    const base = ['/courses', id] as const;
    type Item = { key: CourseNavKey; label: string; icon: string; count: number | null;
                  link: unknown[]; query: Record<string, string> };

    // Learner view (Canvas-style): no Pages/Quizzes/Assignments/People as separate
    // tabs — learners move through content via Modules.
    if (!this.isAdmin) {
      return [
        { key: 'home',     label: 'Home',     icon: 'home',        count: null,               link: [...base],           query: {} },
        { key: 'modules',  label: 'Modules',  icon: 'view_module', count: c?.modules ?? null, link: [...base],           query: { section: 'modules' } },
        { key: 'grades',   label: 'Grades',   icon: 'grading',     count: null,               link: [...base, 'grades'], query: {} },
        { key: 'syllabus', label: 'Syllabus', icon: 'menu_book',   count: null,               link: [...base],           query: { section: 'syllabus' } },
      ] as Item[];
    }

    // Admin / instructor view — full authoring nav.
    return [
      { key: 'home',        label: 'Home',        icon: 'home',        count: null,                   link: [...base],            query: {} },
      { key: 'modules',     label: 'Modules',     icon: 'view_module', count: c?.modules ?? null,     link: [...base],            query: { section: 'modules' } },
      { key: 'pages',       label: 'Pages',       icon: 'description', count: c?.pages ?? null,       link: [...base, 'pages'],   query: {} },
      { key: 'quizzes',     label: 'Quizzes',     icon: 'quiz',        count: c?.quizzes ?? null,     link: [...base, 'quizzes'], query: {} },
      { key: 'assignments', label: 'Assignments', icon: 'assignment',  count: c?.assignments ?? null, link: [...base],            query: { section: 'assignments' } },
      { key: 'people',      label: 'People',      icon: 'group',       count: c?.people ?? null,      link: [...base],            query: { section: 'people' } },
      { key: 'syllabus',    label: 'Syllabus',    icon: 'menu_book',   count: null,                   link: [...base],            query: { section: 'syllabus' } },
    ] as Item[];
  });

  ngOnInit(): void {
    if (!this.counts()) this.fetchCounts();
  }

  private fetchCounts(): void {
    const id = this.courseId();
    forkJoin({
      course:      this.cSvc.getById(id).pipe(catchError(() => of(null))),
      quizzes:     this.qSvc.getByCourse(id).pipe(catchError(() => of([]))),
      assignments: this.aSvc.getByCourse(id).pipe(catchError(() => of([]))),
      enrollments: this.isAdmin ? this.cSvc.getEnrollments(id).pipe(catchError(() => of([]))) : of([]),
    }).subscribe(r => {
      this.fetched.set({
        modules: r.course?.modules.length ?? 0,
        pages: r.course?.pages.length ?? 0,
        quizzes: r.quizzes.length,
        assignments: r.assignments.length,
        people: r.enrollments.length,
      });
    });
  }
}
